'use client'

import { useState } from 'react'
import Link from 'next/link'
import { enqueue } from '@/lib/syncQueue'
import type { Book } from '@/types'

type ItemType = 'book' | 'article' | 'podcast'

interface Props {
  onClose: () => void
  onSuccess: () => void
  upgradeRequired?: boolean
}

export default function AddItemModal({ onClose, onSuccess, upgradeRequired = false }: Props) {
  const [activeTab, setActiveTab] = useState<ItemType>('book')
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')

  // Book fields
  const [bookTitle, setBookTitle] = useState('')
  const [bookAuthor, setBookAuthor] = useState('')
  const [bookPages, setBookPages] = useState('')

  // Article fields
  const [articleTitle, setArticleTitle] = useState('')
  const [articleAuthor, setArticleAuthor] = useState('')
  const [articlePublication, setArticlePublication] = useState('')
  const [articleDate, setArticleDate] = useState('')

  // Podcast fields
  const [podcastTitle, setPodcastTitle] = useState('')
  const [podcastShow, setPodcastShow] = useState('')
  const [podcastGuests, setPodcastGuests] = useState('')
  const [podcastDate, setPodcastDate] = useState('')

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError('')

    let body: Record<string, string | number> = {}

    if (activeTab === 'book') {
      if (!bookTitle.trim()) { setError('Title is required'); return }
      if (!bookPages || Number(bookPages) < 1) { setError('Total pages is required'); return }
      body = {
        type: 'book',
        title: bookTitle.trim(),
        author: bookAuthor.trim(),
        total_pages: Number(bookPages),
      }
    } else if (activeTab === 'article') {
      if (!articleTitle.trim()) { setError('Title is required'); return }
      body = {
        type: 'article',
        title: articleTitle.trim(),
        author: articleAuthor.trim(),
        publication: articlePublication.trim(),
        article_date: articleDate.trim(),
      }
    } else {
      if (!podcastTitle.trim()) { setError('Episode title is required'); return }
      body = {
        type: 'podcast',
        title: podcastTitle.trim(),
        show_title: podcastShow.trim(),
        guests: podcastGuests.trim(),
        air_date: podcastDate.trim(),
      }
    }

    setLoading(true)
    try {
      const res = await fetch('/api/books', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      })
      if (res.ok) {
        onSuccess()
        onClose()
      } else {
        const json = await res.json()
        setError(json.error ?? 'Something went wrong')
      }
    } catch {
      // Network error — queue for sync when back online
      const tempId = `temp_${crypto.randomUUID()}`
      const now = new Date().toISOString()
      const localBook: Book = {
        id: tempId,
        title: (body.title as string) ?? '',
        type: activeTab,
        author: (body.author as string) || null,
        current_page: 0,
        total_pages: activeTab === 'book' ? ((body.total_pages as number) ?? 0) : null,
        publication: activeTab === 'article' ? ((body.publication as string) || null) : null,
        article_date: activeTab === 'article' ? ((body.article_date as string) || null) : null,
        show_title: activeTab === 'podcast' ? ((body.show_title as string) || null) : null,
        guests: activeTab === 'podcast' ? ((body.guests as string) || null) : null,
        air_date: activeTab === 'podcast' ? ((body.air_date as string) || null) : null,
        folder_name: null,
        sessions_per_week: 4,
        sort_order: null,
        status: 'active',
        date_finished: null,
        created_at: now,
        updated_at: now,
      }
      await enqueue({ method: 'POST', url: '/api/books', body, tempId, localBook })
      window.dispatchEvent(new Event('mindwell-queue-updated'))
      onSuccess()
      onClose()
    }
    setLoading(false)
  }

  const TABS: { key: ItemType; label: string }[] = [
    { key: 'book', label: 'Book' },
    { key: 'article', label: 'Article' },
    { key: 'podcast', label: 'Podcast' },
  ]

  const inputClass = 'w-full bg-fog-100 border border-fog-300 rounded-lg px-3 py-2 text-sm text-navy-900 placeholder:text-fog-400 focus:outline-none focus:ring-2 focus:ring-navy-500/20 transition-all'
  const labelClass = 'block text-xs font-medium text-fog-600 mb-1'

  return (
    <div
      className="fixed inset-0 bg-navy-900/40 backdrop-blur-sm flex items-center justify-center z-50 p-4"
      onClick={e => { if (e.target === e.currentTarget) onClose() }}
    >
      <div className="bg-white rounded-2xl shadow-[0_24px_80px_rgba(14,30,53,0.2)] w-full max-w-md">
        {/* Header */}
        <div className="px-6 pt-6 pb-4">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-base font-semibold text-navy-900">Add New</h2>
            <button
              onClick={onClose}
              className="text-fog-400 hover:text-navy-700 text-xl leading-none transition-colors"
            >
              ×
            </button>
          </div>

          {/* Type tabs */}
          <div className="flex gap-1 bg-fog-100 rounded-xl p-1">
            {TABS.map(tab => (
              <button
                key={tab.key}
                onClick={() => { setActiveTab(tab.key); setError('') }}
                className={`flex-1 py-1.5 rounded-lg text-sm font-medium transition-all ${
                  activeTab === tab.key
                    ? 'bg-white text-navy-700 shadow-sm'
                    : 'text-fog-500 hover:text-navy-600'
                }`}
              >
                {tab.label}
              </button>
            ))}
          </div>
        </div>

        {/* Upgrade gate */}
        {upgradeRequired && (
          <div className="px-6 pb-8 text-center">
            <p className="text-2xl mb-3">🔒</p>
            <p className="text-sm font-semibold text-navy-900 mb-1">Free tier limit reached</p>
            <p className="text-sm text-fog-600 leading-relaxed mb-5">
              You&rsquo;ve hit the 3-item limit. Upgrade to Pro for unlimited works.
            </p>
            <Link
              href="/pricing"
              className="inline-block bg-navy-700 hover:bg-navy-800 text-white px-6 py-2.5 rounded-full text-sm font-semibold transition-all"
            >
              View plans →
            </Link>
          </div>
        )}

        {/* Form */}
        {!upgradeRequired && <form onSubmit={handleSubmit} className="px-6 pb-6 space-y-4">
          {activeTab === 'book' && (
            <>
              <div>
                <label className={labelClass}>Title <span className="text-ember-500">*</span></label>
                <input
                  autoFocus
                  value={bookTitle}
                  onChange={e => setBookTitle(e.target.value)}
                  placeholder="Book title"
                  className={inputClass}
                />
              </div>
              <div>
                <label className={labelClass}>Author</label>
                <input
                  value={bookAuthor}
                  onChange={e => setBookAuthor(e.target.value)}
                  placeholder="Author name"
                  className={inputClass}
                />
              </div>
              <div>
                <label className={labelClass}>Total Pages <span className="text-ember-500">*</span></label>
                <input
                  type="number"
                  min={1}
                  value={bookPages}
                  onChange={e => setBookPages(e.target.value)}
                  placeholder="350"
                  className={inputClass}
                />
              </div>
            </>
          )}

          {activeTab === 'article' && (
            <>
              <div>
                <label className={labelClass}>Title <span className="text-ember-500">*</span></label>
                <input
                  autoFocus
                  value={articleTitle}
                  onChange={e => setArticleTitle(e.target.value)}
                  placeholder="Article title"
                  className={inputClass}
                />
              </div>
              <div>
                <label className={labelClass}>Author</label>
                <input
                  value={articleAuthor}
                  onChange={e => setArticleAuthor(e.target.value)}
                  placeholder="Author name"
                  className={inputClass}
                />
              </div>
              <div>
                <label className={labelClass}>Publication</label>
                <input
                  value={articlePublication}
                  onChange={e => setArticlePublication(e.target.value)}
                  placeholder="The Atlantic, Wired…"
                  className={inputClass}
                />
              </div>
              <div>
                <label className={labelClass}>Date</label>
                <input
                  value={articleDate}
                  onChange={e => setArticleDate(e.target.value)}
                  placeholder="March 2025"
                  className={inputClass}
                />
              </div>
            </>
          )}

          {activeTab === 'podcast' && (
            <>
              <div>
                <label className={labelClass}>Episode Title <span className="text-ember-500">*</span></label>
                <input
                  autoFocus
                  value={podcastTitle}
                  onChange={e => setPodcastTitle(e.target.value)}
                  placeholder="Episode title"
                  className={inputClass}
                />
              </div>
              <div>
                <label className={labelClass}>Show Title</label>
                <input
                  value={podcastShow}
                  onChange={e => setPodcastShow(e.target.value)}
                  placeholder="Show name"
                  className={inputClass}
                />
              </div>
              <div>
                <label className={labelClass}>Guests</label>
                <input
                  value={podcastGuests}
                  onChange={e => setPodcastGuests(e.target.value)}
                  placeholder="Guest names"
                  className={inputClass}
                />
              </div>
              <div>
                <label className={labelClass}>Air Date</label>
                <input
                  value={podcastDate}
                  onChange={e => setPodcastDate(e.target.value)}
                  placeholder="March 2025"
                  className={inputClass}
                />
              </div>
            </>
          )}

          {error && (
            <p className="text-sm text-rose-600">{error}</p>
          )}

          <div className="flex gap-3 pt-1">
            <button
              type="button"
              onClick={onClose}
              className="flex-1 bg-fog-100 hover:bg-fog-200 text-navy-700 px-4 py-2.5 rounded-full text-sm font-medium transition-all"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={loading}
              className="flex-1 bg-navy-700 hover:bg-navy-800 text-white px-4 py-2.5 rounded-full text-sm font-semibold transition-all disabled:opacity-50"
            >
              {loading ? 'Adding…' : `Add ${activeTab === 'podcast' ? 'Episode' : activeTab.charAt(0).toUpperCase() + activeTab.slice(1)}`}
            </button>
          </div>
        </form>}
      </div>
    </div>
  )
}

'use client'

import { Suspense, useState, useEffect, useCallback, useRef } from 'react'
import { useRouter, useSearchParams } from 'next/navigation'
import { format, parseISO } from 'date-fns'
import { supabase } from '@/lib/supabase'
import { cacheBooks, getCachedBooks } from '@/lib/localCache'
import { getPendingBooks, processQueue } from '@/lib/syncQueue'
import {
  DndContext,
  closestCenter,
  DragEndEvent,
  DragOverlay,
  DragStartEvent,
  PointerSensor,
  useDroppable,
  useSensor,
  useSensors,
} from '@dnd-kit/core'
import {
  SortableContext,
  useSortable,
  verticalListSortingStrategy,
  arrayMove,
} from '@dnd-kit/sortable'
import { CSS } from '@dnd-kit/utilities'
import AddItemModal from '@/components/AddItemModal'
import DetailModal from '@/components/DetailModal'
import GlobalSearch from '@/components/GlobalSearch'
import { useAuth } from '@/components/AuthProvider'
import RecentlyViewedDropdown from '@/components/RecentlyViewedDropdown'
import { trackRecentlyViewed } from '@/lib/recentlyViewed'
import type { Book } from '@/types'

const READING_SECTION = '__reading-now__'
const QUEUE_SECTION = '__next-up__'

// ── Drag handle ────────────────────────────────────────────────────────────────

function DragHandle() {
  return (
    <svg width="12" height="16" viewBox="0 0 12 16" fill="currentColor">
      <circle cx="4" cy="3" r="1.5" />
      <circle cx="8" cy="3" r="1.5" />
      <circle cx="4" cy="8" r="1.5" />
      <circle cx="8" cy="8" r="1.5" />
      <circle cx="4" cy="13" r="1.5" />
      <circle cx="8" cy="13" r="1.5" />
    </svg>
  )
}

// ── Complete check button ──────────────────────────────────────────────────────

function CompleteButton({ onClick, loading = false }: { onClick: () => void; loading?: boolean }) {
  return (
    <button
      onClick={e => { e.stopPropagation(); onClick() }}
      disabled={loading}
      className="w-7 h-7 flex items-center justify-center rounded-full text-fog-400 hover:text-white hover:bg-navy-700 transition-all disabled:opacity-40 shrink-0"
      title="Mark complete"
    >
      {loading ? (
        <span className="text-[10px]">…</span>
      ) : (
        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-3.5 h-3.5">
          <path fillRule="evenodd" d="M16.704 4.153a.75.75 0 0 1 .143 1.052l-8 10.5a.75.75 0 0 1-1.127.075l-4.5-4.5a.75.75 0 0 1 1.06-1.06l3.894 3.893 7.48-9.817a.75.75 0 0 1 1.05-.143Z" clipRule="evenodd" />
        </svg>
      )}
    </button>
  )
}

// ── Folder pill (shows assigned folder with remove) ─────────────────────────────

function FolderPill({ name, onRemove }: { name: string; onRemove: () => void }) {
  return (
    <span className="inline-flex items-center gap-1 text-[10px] px-2 py-0.5 rounded-full bg-amber-50 text-amber-700 border border-amber-200 max-w-[120px]">
      <span className="truncate">{name}</span>
      <button
        onClick={e => { e.stopPropagation(); onRemove() }}
        className="text-amber-400 hover:text-amber-700 transition-colors shrink-0 leading-none"
        aria-label="Remove folder"
      >
        ×
      </button>
    </span>
  )
}

// ── Folder picker dropdown ──────────────────────────────────────────────────────

function FolderPicker({
  book,
  allBooks,
  onAssign,
}: {
  book: Book
  allBooks: Book[]
  onAssign: (bookId: string, folderName: string | null) => Promise<void>
}) {
  const [open, setOpen] = useState(false)
  const [creating, setCreating] = useState(false)
  const [newName, setNewName] = useState('')
  const ref = useRef<HTMLDivElement>(null)
  const inputRef = useRef<HTMLInputElement>(null)

  const existingFolders = Array.from(
    new Set(allBooks.map(b => b.folder_name).filter((f): f is string => !!f))
  ).sort((a, b) => a.localeCompare(b))

  useEffect(() => {
    if (!open) return
    function handleClick(e: MouseEvent) {
      if (ref.current && !ref.current.contains(e.target as Node)) {
        setOpen(false)
        setCreating(false)
        setNewName('')
      }
    }
    function handleKey(e: KeyboardEvent) {
      if (e.key === 'Escape') {
        setOpen(false)
        setCreating(false)
        setNewName('')
      }
    }
    document.addEventListener('pointerdown', handleClick)
    document.addEventListener('keydown', handleKey)
    return () => {
      document.removeEventListener('pointerdown', handleClick)
      document.removeEventListener('keydown', handleKey)
    }
  }, [open])

  useEffect(() => {
    if (creating) inputRef.current?.focus()
  }, [creating])

  function handleSelect(folder: string) {
    onAssign(book.id, folder)
    setOpen(false)
    setCreating(false)
    setNewName('')
  }

  function handleCreate() {
    const trimmed = newName.trim()
    if (!trimmed) return
    onAssign(book.id, trimmed)
    setOpen(false)
    setCreating(false)
    setNewName('')
  }

  return (
    <div ref={ref} className="relative shrink-0">
      <button
        onClick={e => { e.stopPropagation(); setOpen(o => !o) }}
        className="w-7 h-7 flex items-center justify-center rounded-full text-fog-400 hover:text-navy-700 hover:bg-fog-100 transition-all"
        title="Assign folder"
      >
        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-3.5 h-3.5">
          <path d="M3.75 3A1.75 1.75 0 0 0 2 4.75v3.26a3.235 3.235 0 0 1 1.75-.51h12.5c.644 0 1.245.188 1.75.51V6.75A1.75 1.75 0 0 0 16.25 5h-4.836a.25.25 0 0 1-.177-.073L9.823 3.513A1.75 1.75 0 0 0 8.586 3H3.75ZM3.75 9A1.75 1.75 0 0 0 2 10.75v4.5c0 .966.784 1.75 1.75 1.75h12.5A1.75 1.75 0 0 0 18 15.25v-4.5A1.75 1.75 0 0 0 16.25 9H3.75Z" />
        </svg>
      </button>

      {open && (
        <div
          className="absolute right-0 top-full mt-1 w-52 bg-white rounded-xl border border-fog-300 shadow-lg z-50 py-1 overflow-hidden"
          onClick={e => e.stopPropagation()}
        >
          {/* New folder */}
          {creating ? (
            <div className="px-3 py-2 flex items-center gap-1.5">
              <input
                ref={inputRef}
                type="text"
                value={newName}
                onChange={e => setNewName(e.target.value)}
                onKeyDown={e => { if (e.key === 'Enter') handleCreate() }}
                placeholder="Folder name"
                className="flex-1 min-w-0 text-sm px-2 py-1 rounded-lg border border-fog-300 focus:border-navy-400 focus:outline-none"
              />
              <button
                onClick={handleCreate}
                disabled={!newName.trim()}
                className="text-xs font-medium text-navy-700 hover:text-navy-900 px-2 py-1 rounded-lg hover:bg-fog-100 transition-all disabled:opacity-30"
              >
                Add
              </button>
            </div>
          ) : (
            <button
              onClick={() => setCreating(true)}
              className="w-full text-left px-3 py-2 text-sm text-navy-700 hover:bg-fog-100 transition-colors"
            >
              Add to new folder…
            </button>
          )}

          {/* Existing folders */}
          {existingFolders.length > 0 && (
            <>
              <div className="border-t border-fog-200 my-1" />
              {existingFolders.map(folder => (
                <button
                  key={folder}
                  onClick={() => handleSelect(folder)}
                  className={`w-full text-left px-3 py-2 text-sm hover:bg-fog-100 transition-colors truncate ${
                    book.folder_name === folder ? 'text-amber-700 font-medium' : 'text-navy-800'
                  }`}
                >
                  {folder}
                </button>
              ))}
            </>
          )}
        </div>
      )}
    </div>
  )
}

