function typeEmoji(type: Book['type']): string {
  if (type === 'article') return '📰'
  if (type === 'podcast') return '🎙️'
  return '📚'
}

function CompletedMediaSection({
  books,
  articles,
  podcasts,
  onOpenDetail,
}: {
  books: Book[]
  articles: Book[]
  podcasts: Book[]
  onOpenDetail: (book: Book) => void
}) {
  const router = useRouter()

  function sortRecent(items: Book[]) {
    return [...items].sort((a, b) =>
      (b.date_finished ?? b.created_at ?? '').localeCompare(a.date_finished ?? a.created_at ?? '')
    )
  }

  const recentBooks = sortRecent(books).slice(0, 2)
  const recentArticles = sortRecent(articles).slice(0, 2)
  const recentPodcasts = sortRecent(podcasts).slice(0, 2)
  const combined = [...recentBooks, ...recentArticles, ...recentPodcasts]

  if (combined.length === 0) return null

  return (
    <section>
      <h2 className="text-[11px] font-bold uppercase tracking-widest text-[#cc5500] mb-3">
        Complete
      </h2>
      <div className="space-y-1.5">
        {combined.map(book => (
          <button
            key={book.id}
            onClick={() => onOpenDetail(book)}
            className="w-full text-left bg-white rounded-xl border border-fog-300 shadow-sm px-4 py-3 flex items-center gap-3 hover:border-fog-400 hover:shadow-md transition-all group"
          >
            <div className="flex-1 min-w-0">
              <p className="text-sm font-medium text-navy-800 truncate group-hover:text-navy-900">
                {typeEmoji(book.type)} {book.title}
              </p>
              {book.author && (
                <p className="text-xs text-fog-400 mt-0.5 truncate">{book.author}</p>
              )}
            </div>
            {book.date_finished && (
              <span className="text-xs text-fog-400 shrink-0">
                {format(parseISO(book.date_finished), 'MMM d, yyyy')}
              </span>
            )}
            <span className="text-xs text-ember-600 font-medium shrink-0">✓</span>
          </button>
        ))}

        <button
          onClick={() => router.push('/completed')}
          className="w-full text-center text-xs text-fog-500 hover:text-navy-700 bg-white border border-fog-300 hover:border-fog-400 rounded-xl py-2.5 mt-1 transition-all font-medium"
