            )
          })()}

          {activeTab === 'quotes' && (
            <Quotes
              bookId={bookId}
              quotes={quotes}
              onUpdate={setQuotes}
            />
          )}
        </div>

        {/* Link Quote Modal */}
        {showLinkModal && (
          <LinkQuoteModal
            quotes={quotes}
            bookId={bookId}
            onInsert={handleInsertQuoteLink}
            onClose={() => { setShowLinkModal(false); pendingInsert.current = null }}
            onQuoteAdded={q => setQuotes(prev => [...prev, q])}
          />
        )}
      </div>
    </div>
  )
}

import { NextRequest } from 'next/server'
import { createSupabaseServerClient } from '@/lib/supabase-server'

export async function GET() {
  const supabase = await createSupabaseServerClient()
  const { data, error } = await supabase
    .from('books')
    .select('*')
    .order('created_at', { ascending: false })
  if (error) return Response.json({ error: error.message }, { status: 500 })
  return Response.json(data)
}

export async function POST(req: NextRequest) {
  const supabase = await createSupabaseServerClient()
  const body = await req.json()
  const {
    title,
    type = 'book',
    author,
    current_page = 0,
    total_pages,
    sessions_per_week = 4,
    // Article fields
    publication,
    article_date,
    // Podcast fields
    show_title,
    guests,
    air_date,
  } = body

  if (!title) {
    return Response.json({ error: 'title is required' }, { status: 400 })
  }
  if (type === 'book' && !total_pages) {
    return Response.json({ error: 'total_pages is required for books' }, { status: 400 })
  }

  // Compute sort_order: next available slot among active items of this type
  const { data: existingBooks } = await supabase
    .from('books')
    .select('sort_order')
    .eq('status', 'active')
    .eq('type', type)

  const maxOrder = Math.max(0, ...((existingBooks ?? []).map((b: { sort_order: number | null }) => b.sort_order ?? 0)))
  const sort_order = maxOrder + 1

  const { data: book, error: bookError } = await supabase
    .from('books')
    .insert({
      title,
      type,
      author: author ?? null,
      current_page: type === 'book' ? (current_page ?? 0) : 0,
      total_pages: type === 'book' ? (total_pages ?? 0) : 0,
      sessions_per_week,
      status: 'active',
      sort_order,
      publication: type === 'article' ? (publication ?? null) : null,
      article_date: type === 'article' ? (article_date ?? null) : null,
      show_title: type === 'podcast' ? (show_title ?? null) : null,
      guests: type === 'podcast' ? (guests ?? null) : null,
      air_date: type === 'podcast' ? (air_date ?? null) : null,
    })
    .select()
    .single()
  if (bookError) return Response.json({ error: bookError.message }, { status: 500 })

  return Response.json({ book }, { status: 201 })
}

import { NextRequest } from 'next/server'
import { createSupabaseServerClient } from '@/lib/supabase-server'

export async function GET(
  _req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const supabase = await createSupabaseServerClient()
  const { id } = await params
  const { data, error } = await supabase.from('books').select('*').eq('id', id).single()
  if (error) return Response.json({ error: error.message }, { status: 404 })
  return Response.json(data)
}

export async function PATCH(
  req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const supabase = await createSupabaseServerClient()
  const { id } = await params
  const body = await req.json()

  console.log('[PATCH /api/books/%s] received body:', id, JSON.stringify(body))

  const { data: updatedBook, error } = await supabase
    .from('books')
    .update(body)
    .eq('id', id)
    .select()
    .single()

  if (error) {
    console.error('[PATCH /api/books/%s] Supabase error:', id, error.message, error.details, error.hint)
    return Response.json({ error: error.message }, { status: 500 })
  }

  console.log('[PATCH /api/books/%s] updated OK:', id, JSON.stringify(updatedBook))
  return Response.json(updatedBook)
}

export async function DELETE(
  _req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const supabase = await createSupabaseServerClient()
  const { id } = await params
  const { error } = await supabase.from('books').delete().eq('id', id)
  if (error) return Response.json({ error: error.message }, { status: 500 })
  return new Response(null, { status: 204 })
}

