'use client'

import { useState } from 'react'
import Link from 'next/link'
import { enqueue } from '@/lib/syncQueue'
import type { Book } from '@/types'

type ItemType = 'book' | 'article' | 'podcast'

interface Props {
  onClose: () => void
  onSuccess: () => void
  upgradeRequired?: boolean
}

