'use client'

import { useState, useEffect } from 'react'
import { useRouter } from 'next/navigation'
import { format, parseISO } from 'date-fns'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/components/AuthProvider'
import type { Book } from '@/types'

const TYPE_EMOJI: Record<string, string> = {
  book: '📚',
  article: '📰',
  podcast: '🎙️',
}

export default function CompletedPage() {
  const router = useRouter()
  const { signOut } = useAuth()
  const [books, setBooks] = useState<Book[]>([])
  const [loading, setLoading] = useState(true)

import { NextRequest } from 'next/server'
import { createSupabaseServerClient } from '@/lib/supabase-server'

export async function GET() {
  const supabase = await createSupabaseServerClient()
  const { data, error } = await supabase
    .from('books')
    .select('*')
    .order('created_at', { ascending: false })
  if (error) return Response.json({ error: error.message }, { status: 500 })
  return Response.json(data)
}

export async function POST(req: NextRequest) {
  const supabase = await createSupabaseServerClient()
  const body = await req.json()
  const {
    title,
    type = 'book',
    author,
    current_page = 0,
    total_pages,
    sessions_per_week = 4,
    // Article fields
    publication,
    article_date,
    // Podcast fields
    show_title,
    guests,
    air_date,
    // Media link (articles & podcasts)
    media_link,
  } = body

  if (!title) {
    return Response.json({ error: 'title is required' }, { status: 400 })
  }
  if (type === 'book' && !total_pages) {
    return Response.json({ error: 'total_pages is required for books' }, { status: 400 })
  }

  // Compute sort_order: next available slot among active items of this type
  const { data: existingBooks } = await supabase
    .from('books')
    .select('sort_order')
    .eq('status', 'active')
    .eq('type', type)

  const maxOrder = Math.max(0, ...((existingBooks ?? []).map((b: { sort_order: number | null }) => b.sort_order ?? 0)))
  const sort_order = maxOrder + 1

  const { data: book, error: bookError } = await supabase
    .from('books')
    .insert({
      title,
      type,
      author: author ?? null,
      current_page: type === 'book' ? (current_page ?? 0) : 0,
      total_pages: type === 'book' ? (total_pages ?? 0) : 0,
      sessions_per_week,
      status: 'active',
      sort_order,
      publication: type === 'article' ? (publication ?? null) : null,
      article_date: type === 'article' ? (article_date ?? null) : null,
      show_title: type === 'podcast' ? (show_title ?? null) : null,
      guests: type === 'podcast' ? (guests ?? null) : null,
      air_date: type === 'podcast' ? (air_date ?? null) : null,
      media_link: (type === 'article' || type === 'podcast') ? (media_link ?? null) : null,
    })
    .select()
    .single()
  if (bookError) return Response.json({ error: bookError.message }, { status: 500 })

  return Response.json({ book }, { status: 201 })
}

import { NextRequest } from 'next/server'
import Anthropic from '@anthropic-ai/sdk'

export async function POST(req: NextRequest) {
  const apiKey = process.env.ANTHROPIC_API_KEY
  if (!apiKey) {
    return Response.json({ error: 'ANTHROPIC_API_KEY not configured' }, { status: 500 })
  }

  let url: string
  let type: 'article' | 'podcast'

  try {
    const body = await req.json()
    url = body.url
    type = body.type
    if (!url || !type) throw new Error('missing fields')
  } catch {
    return Response.json({ error: 'Invalid request body' }, { status: 400 })
  }

  try {
    const client = new Anthropic({ apiKey })

    const prompt = `Given this URL for a${type === 'article' ? 'n article' : ' podcast episode'}: ${url}

Analyze the URL structure and any publicly known metadata about the source (domain, path segments, query parameters, known publications/shows) to infer as much as you can about this ${type}.

Return a JSON object with these fields (use null for any you cannot determine):
- title: string | null (the title of the ${type === 'article' ? 'article' : 'episode'})
- author: string | null (the author, for articles)
- publication: string | null (the publication name, for articles)
- date: string | null (publication or air date, as a human-readable string like "March 2025")
- show_title: string | null (the podcast show name, for podcasts)
- guests: string | null (podcast guests, comma-separated)
- description: string | null (brief description if inferrable)

Return ONLY the JSON object, no other text.`

    const message = await client.messages.create({
      model: 'claude-sonnet-4-20250514',
      max_tokens: 1024,
      messages: [{ role: 'user', content: prompt }],
    })

    const text = message.content
      .filter((block): block is Anthropic.TextBlock => block.type === 'text')
      .map(block => block.text)
      .join('')

    // Extract JSON from the response (handle potential markdown code blocks)
    const jsonMatch = text.match(/\{[\s\S]*\}/)
    if (!jsonMatch) {
      return Response.json({})
    }

    const parsed = JSON.parse(jsonMatch[0])
    return Response.json(parsed)
  } catch (err) {
    console.error('[autofill-media] Error:', err)
    return Response.json({})
  }
}

