import { NextRequest } from 'next/server'
import Anthropic from '@anthropic-ai/sdk'

interface PageMeta {
  title?: string
  ogTitle?: string
  ogDescription?: string
  ogSiteName?: string
  articleAuthor?: string
  articlePublishedTime?: string
  ogAudio?: string
}

async function fetchPageMeta(url: string): Promise<PageMeta | null> {
  try {
    const res = await fetch(url, {
      headers: { 'User-Agent': 'Mozilla/5.0' },
      signal: AbortSignal.timeout(8000),
    })
    if (!res.ok) return null

    const html = await res.text()
    const meta: PageMeta = {}

    const titleMatch = html.match(/<title[^>]*>([^<]*)<\/title>/i)
    if (titleMatch) meta.title = titleMatch[1].trim()

    const metaTags: [keyof PageMeta, string][] = [
      ['ogTitle', 'og:title'],
      ['ogDescription', 'og:description'],
      ['ogSiteName', 'og:site_name'],
      ['articleAuthor', 'article:author'],
      ['articlePublishedTime', 'article:published_time'],
      ['ogAudio', 'og:audio'],
    ]

    for (const [key, property] of metaTags) {
      const pattern = new RegExp(
        `<meta[^>]*property=["']${property.replace(':', '\\:')}["'][^>]*content=["']([^"']*)["']|<meta[^>]*content=["']([^"']*)["'][^>]*property=["']${property.replace(':', '\\:')}["']`,
        'i'
      )
      const match = html.match(pattern)
      if (match) meta[key] = (match[1] ?? match[2]).trim()
    }

    return meta
  } catch {
    return null
  }
}

export async function POST(req: NextRequest) {
  const apiKey = process.env.ANTHROPIC_API_KEY
  if (!apiKey) {
    return Response.json({ error: 'ANTHROPIC_API_KEY not configured' }, { status: 500 })
  }

  let url: string
  let type: 'article' | 'podcast'

  try {
    const body = await req.json()
    url = body.url
    type = body.type
    if (!url || !type) throw new Error('missing fields')
  } catch {
    return Response.json({ error: 'Invalid request body' }, { status: 400 })
  }

  try {
    const client = new Anthropic({ apiKey })
    const meta = await fetchPageMeta(url)

    let metaContext: string
    if (meta && Object.keys(meta).length > 0) {
      const lines = [
        meta.title && `Page title: ${meta.title}`,
        meta.ogTitle && `og:title: ${meta.ogTitle}`,
        meta.ogDescription && `og:description: ${meta.ogDescription}`,
        meta.ogSiteName && `og:site_name: ${meta.ogSiteName}`,
        meta.articleAuthor && `article:author: ${meta.articleAuthor}`,
        meta.articlePublishedTime && `article:published_time: ${meta.articlePublishedTime}`,
        meta.ogAudio && `og:audio: ${meta.ogAudio}`,
      ].filter(Boolean).join('\n')

      metaContext = `I fetched the page and extracted these meta tags:\n${lines}\n\nUse this metadata to determine the fields below.`
    } else {
      metaContext = `I could not fetch the page. Analyze the URL structure and any publicly known metadata about the source (domain, path segments, query parameters, known publications/shows) to infer what you can.`
    }

    const prompt = `Given this URL for a${type === 'article' ? 'n article' : ' podcast episode'}: ${url}

${metaContext}

Return a JSON object with these fields (use null for any you cannot determine):
- title: string | null (the title of the ${type === 'article' ? 'article' : 'episode'})
- author: string | null (the author, for articles)
- publication: string | null (the publication name, for articles)
- date: string | null (publication or air date, as a human-readable string like "March 2025")
- show_title: string | null (the podcast show name, for podcasts)
- guests: string | null (podcast guests, comma-separated)
- description: string | null (brief description if inferrable)

Return ONLY the JSON object, no other text.`

    const message = await client.messages.create({
      model: 'claude-sonnet-4-20250514',
      max_tokens: 1024,
      messages: [{ role: 'user', content: prompt }],
    })

    const text = message.content
      .filter((block): block is Anthropic.TextBlock => block.type === 'text')
      .map(block => block.text)
