'use client'

import { useState, useRef } from 'react'
import Link from 'next/link'
import { enqueue } from '@/lib/syncQueue'
import type { Book } from '@/types'

type ItemType = 'book' | 'article' | 'podcast'

interface Props {
  onClose: () => void
  onSuccess: () => void
  upgradeRequired?: boolean
}

export default function AddItemModal({ onClose, onSuccess, upgradeRequired = false }: Props) {
  const [activeTab, setActiveTab] = useState<ItemType>('book')
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')

  // Book fields
  const [bookTitle, setBookTitle] = useState('')
  const [bookAuthor, setBookAuthor] = useState('')
  const [bookPages, setBookPages] = useState('')

  // Article fields
  const [articleLink, setArticleLink] = useState('')
  const [articleTitle, setArticleTitle] = useState('')
  const [articleAuthor, setArticleAuthor] = useState('')
  const [articlePublication, setArticlePublication] = useState('')
  const [articleDate, setArticleDate] = useState('')

  // Podcast fields
  const [podcastLink, setPodcastLink] = useState('')
  const [podcastTitle, setPodcastTitle] = useState('')
  const [podcastShow, setPodcastShow] = useState('')
  const [podcastGuests, setPodcastGuests] = useState('')
  const [podcastDate, setPodcastDate] = useState('')

  // AI autofill
  const [autofilling, setAutofilling] = useState(false)
  // Track which fields the user has manually edited
  const touchedFields = useRef<Set<string>>(new Set())

  function markTouched(field: string) {
    touchedFields.current.add(field)
  }

  async function handleAutofill() {
    const url = activeTab === 'article' ? articleLink : podcastLink
    if (!url.trim()) return
    setAutofilling(true)
    try {
      const res = await fetch('/api/autofill-media', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ url: url.trim(), type: activeTab }),
      })
      if (res.ok) {
        const data = await res.json()
        if (activeTab === 'article') {
          if (data.title && !touchedFields.current.has('articleTitle')) setArticleTitle(data.title)
          if (data.author && !touchedFields.current.has('articleAuthor')) setArticleAuthor(data.author)
          if (data.publication && !touchedFields.current.has('articlePublication')) setArticlePublication(data.publication)
          if (data.date && !touchedFields.current.has('articleDate')) setArticleDate(data.date)
        } else {
          if (data.title && !touchedFields.current.has('podcastTitle')) setPodcastTitle(data.title)
          if (data.show_title && !touchedFields.current.has('podcastShow')) setPodcastShow(data.show_title)
          if (data.guests && !touchedFields.current.has('podcastGuests')) setPodcastGuests(data.guests)
          if (data.date && !touchedFields.current.has('podcastDate')) setPodcastDate(data.date)
        }
      }
    } catch {
      // Silently fail — fields remain editable
    }
    setAutofilling(false)
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError('')

    let body: Record<string, string | number> = {}

    if (activeTab === 'book') {
      if (!bookTitle.trim()) { setError('Title is required'); return }
      if (!bookPages || Number(bookPages) < 1) { setError('Total pages is required'); return }
      body = {
        type: 'book',
        title: bookTitle.trim(),
        author: bookAuthor.trim(),
        total_pages: Number(bookPages),
      }
    } else if (activeTab === 'article') {
      if (!articleTitle.trim()) { setError('Title is required'); return }
      body = {
        type: 'article',
        title: articleTitle.trim(),
        author: articleAuthor.trim(),
        publication: articlePublication.trim(),
        article_date: articleDate.trim(),
        media_link: articleLink.trim(),
      }
    } else {
      if (!podcastTitle.trim()) { setError('Episode title is required'); return }
      body = {
        type: 'podcast',
        title: podcastTitle.trim(),
        show_title: podcastShow.trim(),
        guests: podcastGuests.trim(),
        air_date: podcastDate.trim(),
        media_link: podcastLink.trim(),
      }
    }

    setLoading(true)
    try {
      const res = await fetch('/api/books', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      })
      if (res.ok) {
        onSuccess()
        onClose()
      } else {
        const json = await res.json()
        setError(json.error ?? 'Something went wrong')
      }
    } catch {
      // Network error — queue for sync when back online
      const tempId = `temp_${crypto.randomUUID()}`
      const now = new Date().toISOString()
      const localBook: Book = {
        id: tempId,
        title: (body.title as string) ?? '',
        type: activeTab,
        author: (body.author as string) || null,
        current_page: 0,
        total_pages: activeTab === 'book' ? ((body.total_pages as number) ?? 0) : null,
        publication: activeTab === 'article' ? ((body.publication as string) || null) : null,
        article_date: activeTab === 'article' ? ((body.article_date as string) || null) : null,
        show_title: activeTab === 'podcast' ? ((body.show_title as string) || null) : null,
        guests: activeTab === 'podcast' ? ((body.guests as string) || null) : null,
        air_date: activeTab === 'podcast' ? ((body.air_date as string) || null) : null,
        media_link: activeTab !== 'book' ? ((body.media_link as string) || null) : null,
        folder_name: null,
        sessions_per_week: 4,
        sort_order: null,
        status: 'active',
        date_finished: null,
        created_at: now,
        updated_at: now,
      }
      await enqueue({ method: 'POST', url: '/api/books', body, tempId, localBook })
      window.dispatchEvent(new Event('mindwell-queue-updated'))
      onSuccess()
      onClose()
    }
    setLoading(false)
  }

  const TABS: { key: ItemType; label: string }[] = [
    { key: 'book', label: 'Book' },
    { key: 'article', label: 'Article' },
    { key: 'podcast', label: 'Podcast' },
  ]

  const inputClass = 'w-full bg-fog-100 border border-fog-300 rounded-lg px-3 py-2 text-sm text-navy-900 placeholder:text-fog-400 focus:outline-none focus:ring-2 focus:ring-navy-500/20 transition-all'
  const labelClass = 'block text-xs font-medium text-fog-600 mb-1'

  function renderLinkField(value: string, onChange: (v: string) => void) {
    return (
      <div>
        <div className="flex items-center gap-1.5 mb-1">
          <label className="text-xs font-medium text-fog-600">Link</label>
          <button
            type="button"
            onClick={handleAutofill}
            disabled={autofilling || !value.trim()}
            className="inline-flex items-center gap-1 text-[10px] font-semibold px-2 py-0.5 rounded-md bg-amber-50 text-navy-700 border border-amber-200 hover:bg-amber-100 hover:border-amber-300 transition-all disabled:opacity-40 disabled:cursor-not-allowed"
            title="Autofill from link"
          >
            {autofilling ? (
              <span className="inline-block w-3 h-3 border-2 border-navy-700/30 border-t-navy-700 rounded-full animate-spin" />
            ) : (
              <>AI ✦</>
            )}
          </button>
        </div>
        <input
          autoFocus
          value={value}
          onChange={e => onChange(e.target.value)}
          placeholder="https://..."
          className={inputClass}
        />
      </div>
    )
  }

  return (
    <div
      className="fixed inset-0 bg-navy-900/40 backdrop-blur-sm flex items-center justify-center z-50 p-4"
      onClick={e => { if (e.target === e.currentTarget) onClose() }}
    >
      <div className="bg-white rounded-2xl shadow-[0_24px_80px_rgba(14,30,53,0.2)] w-full max-w-md">
        {/* Header */}
        <div className="px-6 pt-6 pb-4">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-base font-semibold text-navy-900">Add New</h2>
            <button
              onClick={onClose}
              className="text-fog-400 hover:text-navy-700 text-xl leading-none transition-colors"
            >
              ×
            </button>
          </div>

          {/* Type tabs */}
          <div className="flex gap-1 bg-fog-100 rounded-xl p-1">
            {TABS.map(tab => (
              <button
                key={tab.key}
                onClick={() => { setActiveTab(tab.key); setError('') }}
                className={`flex-1 py-1.5 rounded-lg text-sm font-medium transition-all ${
                  activeTab === tab.key
                    ? 'bg-white text-navy-700 shadow-sm'
                    : 'text-fog-500 hover:text-navy-600'
                }`}
              >
                {tab.label}
              </button>
            ))}
          </div>
        </div>

        {/* Upgrade gate */}
        {upgradeRequired && (
          <div className="px-6 pb-8 text-center">
            <p className="text-2xl mb-3">🔒</p>
            <p className="text-sm font-semibold text-navy-900 mb-1">Free tier limit reached</p>
            <p className="text-sm text-fog-600 leading-relaxed mb-5">
              You&rsquo;ve hit the 3-item limit. Upgrade to Pro for unlimited works.
            </p>
            <Link
              href="/pricing"
              className="inline-block bg-navy-700 hover:bg-navy-800 text-white px-6 py-2.5 rounded-full text-sm font-semibold transition-all"
            >
              View plans →
            </Link>
          </div>
        )}

        {/* Form */}
        {!upgradeRequired && <form onSubmit={handleSubmit} className="px-6 pb-6 space-y-4">
          {activeTab === 'book' && (
            <>
              <div>
                <label className={labelClass}>Title <span className="text-ember-500">*</span></label>
                <input
                  autoFocus
                  value={bookTitle}
                  onChange={e => setBookTitle(e.target.value)}
                  placeholder="Book title"
                  className={inputClass}
                />
              </div>
              <div>
                <label className={labelClass}>Author</label>
                <input
                  value={bookAuthor}
                  onChange={e => setBookAuthor(e.target.value)}
                  placeholder="Author name"
                  className={inputClass}
                />
              </div>
              <div>
                <label className={labelClass}>Total Pages <span className="text-ember-500">*</span></label>
                <input
                  type="number"
                  min={1}
                  value={bookPages}
                  onChange={e => setBookPages(e.target.value)}
                  placeholder="350"
                  className={inputClass}
                />
              </div>
            </>
          )}

          {activeTab === 'article' && (
            <>
              {renderLinkField(articleLink, setArticleLink)}
              <div>
                <label className={labelClass}>Title <span className="text-ember-500">*</span></label>
                <input
                  value={articleTitle}
                  onChange={e => { setArticleTitle(e.target.value); markTouched('articleTitle') }}
                  placeholder="Article title"
                  className={inputClass}
                />
              </div>
              <div>
                <label className={labelClass}>Author</label>
                <input
                  value={articleAuthor}
                  onChange={e => { setArticleAuthor(e.target.value); markTouched('articleAuthor') }}
                  placeholder="Author name"
                  className={inputClass}
                />
              </div>
              <div>
                <label className={labelClass}>Publication</label>
                <input
                  value={articlePublication}
                  onChange={e => { setArticlePublication(e.target.value); markTouched('articlePublication') }}
                  placeholder="The Atlantic, Wired…"
                  className={inputClass}
                />
              </div>
              <div>
                <label className={labelClass}>Date</label>
                <input
                  value={articleDate}
                  onChange={e => { setArticleDate(e.target.value); markTouched('articleDate') }}
                  placeholder="March 2025"
                  className={inputClass}
                />
              </div>
            </>
          )}

          {activeTab === 'podcast' && (
            <>
              {renderLinkField(podcastLink, setPodcastLink)}
              <div>
                <label className={labelClass}>Episode Title <span className="text-ember-500">*</span></label>
                <input
                  value={podcastTitle}
                  onChange={e => { setPodcastTitle(e.target.value); markTouched('podcastTitle') }}
                  placeholder="Episode title"
                  className={inputClass}
                />
              </div>
              <div>
                <label className={labelClass}>Show Title</label>
                <input
                  value={podcastShow}
                  onChange={e => { setPodcastShow(e.target.value); markTouched('podcastShow') }}
                  placeholder="Show name"
                  className={inputClass}
                />
              </div>
              <div>
                <label className={labelClass}>Guests</label>
                <input
                  value={podcastGuests}
                  onChange={e => { setPodcastGuests(e.target.value); markTouched('podcastGuests') }}
                  placeholder="Guest names"
                  className={inputClass}
                />
              </div>
              <div>
                <label className={labelClass}>Air Date</label>
                <input
                  value={podcastDate}
                  onChange={e => { setPodcastDate(e.target.value); markTouched('podcastDate') }}
                  placeholder="March 2025"
                  className={inputClass}
                />
              </div>
            </>
          )}

          {error && (
            <p className="text-sm text-rose-600">{error}</p>
          )}

          <div className="flex gap-3 pt-1">
            <button
              type="button"
              onClick={onClose}
              className="flex-1 bg-fog-100 hover:bg-fog-200 text-navy-700 px-4 py-2.5 rounded-full text-sm font-medium transition-all"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={loading}
              className="flex-1 bg-navy-700 hover:bg-navy-800 text-white px-4 py-2.5 rounded-full text-sm font-semibold transition-all disabled:opacity-50"
            >
              {loading ? 'Adding…' : `Add ${activeTab === 'podcast' ? 'Episode' : activeTab.charAt(0).toUpperCase() + activeTab.slice(1)}`}
            </button>
          </div>
        </form>}
      </div>
    </div>
  )
}

