  const articleAuthorRef = useRef<HTMLInputElement>(null)
  const podcastTitleRef = useRef<HTMLInputElement>(null)

  const PLACEHOLDER = 'Could not retrieve \u2014 please enter manually'

  function markTouched(field: string) {
    touchedFields.current.add(field)
