              <span className="inline-block w-3 h-3 border-2 border-navy-700/30 border-t-navy-700 rounded-full animate-spin" />
            ) : (
              <>AI ✦</>
            )}
          </button>
        </div>
        <input
          autoFocus
          value={value}
          onChange={e => onChange(e.target.value)}
          placeholder="https://..."
          className={inputClass}
        />
      </div>
    )
  }

